files.content:
.mrg-accordion {
  border-block: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-strong);
  inline-size: 100%;
}

.mrg-accordion__item {
  border-block-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-strong);
}

.mrg-accordion__item:last-child {
  border-block-end: 0;
}

.mrg-accordion__header {
  font: inherit;
  margin: 0;
}

.mrg-accordion__trigger {
  align-items: center;
  background: transparent;
  border: 0;
  box-sizing: border-box;
  color: inherit;
  cursor: pointer;
  display: flex;
  font: inherit;
  font-weight: var(--mrg-semantic-font-weight-strong);
  gap: var(--mrg-semantic-space-inline-md);
  inline-size: 100%;
  justify-content: space-between;
  min-block-size: var(--mrg-semantic-density-control-height);
  padding: var(--mrg-semantic-space-stack-md) var(--mrg-semantic-space-inline-lg);
  text-align: start;
}

.mrg-accordion__trigger[data-hovered] {
  background: var(--mrg-semantic-color-background-surface-sunken);
}

.mrg-accordion__trigger[data-focus-visible] {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: calc(var(--mrg-semantic-focus-width) * -1);
}

.mrg-accordion__trigger[data-disabled] {
  cursor: not-allowed;
  opacity: var(--mrg-semantic-opacity-disabled);
}

[data-slot="accordion-trigger-indicator"] {
  flex: none;
  transition: transform var(--mrg-semantic-motion-duration-feedback)
    var(--mrg-semantic-motion-easing-standard);
}

.mrg-accordion__item[data-expanded] [data-slot="accordion-trigger-indicator"] {
  transform: rotate(180deg);
}

.mrg-accordion__panel {
  min-inline-size: 0;
  padding: 0 var(--mrg-semantic-space-inline-lg) var(--mrg-semantic-space-stack-lg);
}

@media (prefers-reduced-motion: reduce) {
  [data-slot="accordion-trigger-indicator"] {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-accordion__trigger[data-focus-visible] {
    outline-color: Highlight;
  }
}

"use client";

import { forwardRef, type HTMLAttributes, type KeyboardEventHandler, type ReactNode } from "react";
import {
  Button as AriaButton,
  Disclosure as AriaDisclosure,
  DisclosureGroup as AriaDisclosureGroup,
  DisclosurePanel as AriaDisclosurePanel,
  Heading as AriaHeading,
  type ButtonProps as AriaButtonProps,
  type DisclosurePanelProps as AriaDisclosurePanelProps,
  type DisclosureProps as AriaDisclosureProps,
  type HeadingProps as AriaHeadingProps,
} from "react-aria-components/DisclosureGroup";

import "./accordion.css";

export interface AccordionRootProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children" | "defaultValue" | "onChange"
> {
  readonly children: ReactNode;
  readonly defaultValue?: readonly string[];
  readonly disabled?: boolean;
  readonly multiple?: boolean;
  readonly onValueChange?: (value: readonly string[]) => void;
  readonly value?: readonly string[];
}

function validateAccordionValues(values: readonly string[] | undefined, name: string): void {
  if (values === undefined) return;
  const unique = new Set<string>();
  for (const value of values) {
    if (value.trim().length === 0) {
      throw new Error(`Mergora Accordion ${name} values must be non-empty strings.`);
    }
    if (unique.has(value)) {
      throw new Error(`Mergora Accordion ${name} values must be unique.`);
    }
    unique.add(value);
  }
}

function enabledAccordionTriggers(root: HTMLElement): HTMLButtonElement[] {
  return [...root.querySelectorAll<HTMLButtonElement>('[data-slot="accordion-trigger"]')].filter(
    (trigger) => !trigger.disabled && trigger.getAttribute("aria-disabled") !== "true",
  );
}

export const AccordionRoot = forwardRef<HTMLDivElement, AccordionRootProps>(function AccordionRoot(
  {
    children,
    className,
    defaultValue,
    disabled = false,
    multiple = false,
    onKeyDown,
    onValueChange,
    value,
    ...nativeProps
  },
  ref,
) {
  validateAccordionValues(value, "controlled");
  validateAccordionValues(defaultValue, "default");
  if (!multiple && (value?.length ?? 0) > 1) {
    throw new Error("Mergora Accordion single mode accepts at most one controlled value.");
  }
  if (!multiple && (defaultValue?.length ?? 0) > 1) {
    throw new Error("Mergora Accordion single mode accepts at most one default value.");
  }

  const handleKeyDown: KeyboardEventHandler<HTMLDivElement> = (event) => {
    onKeyDown?.(event);
    if (event.defaultPrevented || !(event.target instanceof HTMLButtonElement)) return;
    if (event.target.dataset.slot !== "accordion-trigger") return;
    const triggers = enabledAccordionTriggers(event.currentTarget);
    const current = triggers.indexOf(event.target);
    if (current < 0 || triggers.length === 0) return;
    let next: number | undefined;
    if (event.key === "ArrowDown") next = (current + 1) % triggers.length;
    else if (event.key === "ArrowUp") next = (current - 1 + triggers.length) % triggers.length;
    else if (event.key === "Home") next = 0;
    else if (event.key === "End") next = triggers.length - 1;
    if (next === undefined) return;
    event.preventDefault();
    triggers[next]?.focus();
  };

  return (
    <div
      {...nativeProps}
      className={className === undefined ? "mrg-accordion" : `mrg-accordion ${className}`}
      data-slot="accordion"
      onKeyDown={handleKeyDown}
      ref={ref}
    >
      <AriaDisclosureGroup
        {...(defaultValue === undefined ? {} : { defaultExpandedKeys: defaultValue })}
        {...(value === undefined ? {} : { expandedKeys: value })}
        allowsMultipleExpanded={multiple}
        data-slot="accordion-group"
        isDisabled={disabled}
        onExpandedChange={(keys) => onValueChange?.([...keys].map(String))}
      >
        {children}
      </AriaDisclosureGroup>
    </div>
  );
});

AccordionRoot.displayName = "AccordionRoot";

export interface AccordionItemProps extends Omit<
  AriaDisclosureProps,
  "children" | "className" | "id" | "isDisabled"
> {
  readonly children: ReactNode;
  readonly disabled?: boolean;
  readonly value: string;
}

export const AccordionItem = forwardRef<HTMLDivElement, AccordionItemProps>(function AccordionItem(
  { children, disabled = false, value, ...props },
  ref,
) {
  if (value.trim().length === 0) {
    throw new Error("Mergora Accordion.Item value must be a non-empty string.");
  }
  return (
    <AriaDisclosure
      {...props}
      className="mrg-accordion__item"
      data-slot="accordion-item"
      id={value}
      isDisabled={disabled}
      ref={ref}
    >
      {children}
    </AriaDisclosure>
  );
});

AccordionItem.displayName = "AccordionItem";

export interface AccordionHeaderProps extends Omit<
  AriaHeadingProps,
  "children" | "className" | "level"
> {
  readonly children: ReactNode;
  readonly level: 1 | 2 | 3 | 4 | 5 | 6;
}

export const AccordionHeader = forwardRef<HTMLHeadingElement, AccordionHeaderProps>(
  function AccordionHeader({ children, level, ...props }, ref) {
    return (
      <AriaHeading
        {...props}
        className="mrg-accordion__header"
        data-slot="accordion-header"
        level={level}
        ref={ref}
      >
        {children}
      </AriaHeading>
    );
  },
);

AccordionHeader.displayName = "AccordionHeader";

export interface AccordionTriggerProps extends Omit<AriaButtonProps, "children" | "className"> {
  readonly children: ReactNode;
}

export const AccordionTrigger = forwardRef<HTMLButtonElement, AccordionTriggerProps>(
  function AccordionTrigger({ children, ...props }, ref) {
    return (
      <AriaButton
        {...props}
        className="mrg-accordion__trigger"
        data-slot="accordion-trigger"
        ref={ref}
        slot="trigger"
      >
        <span data-slot="accordion-trigger-label">{children}</span>
        <span aria-hidden="true" data-slot="accordion-trigger-indicator">
          ▾
        </span>
      </AriaButton>
    );
  },
);

AccordionTrigger.displayName = "AccordionTrigger";

export interface AccordionPanelProps extends Omit<
  AriaDisclosurePanelProps,
  "children" | "className"
> {
  readonly children: ReactNode;
}

export const AccordionPanel = forwardRef<HTMLDivElement, AccordionPanelProps>(
  function AccordionPanel({ children, ...props }, ref) {
    return (
      <AriaDisclosurePanel
        {...props}
        className="mrg-accordion__panel"
        data-slot="accordion-panel"
        ref={ref}
      >
        {children}
      </AriaDisclosurePanel>
    );
  },
);

AccordionPanel.displayName = "AccordionPanel";

export const Accordion = {
  Header: AccordionHeader,
  Item: AccordionItem,
  Panel: AccordionPanel,
  Root: AccordionRoot,
  Trigger: AccordionTrigger,
} as const;

.mrg-action-menu {
  box-sizing: border-box;
  display: inline-flex;
  max-inline-size: 100%;
  min-inline-size: 0;
}

.mrg-action-menu-trigger {
  align-items: center;
  appearance: none;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: var(--mrg-semantic-color-foreground-primary);
  cursor: pointer;
  display: inline-flex;
  font: inherit;
  font-weight: var(--mrg-semantic-font-weight-label);
  gap: var(--mrg-semantic-density-control-gap);
  justify-content: space-between;
  max-inline-size: 100%;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  overflow-wrap: anywhere;
  padding-block: var(--mrg-semantic-space-inline-sm);
  padding-inline: var(--mrg-semantic-space-inline-lg);
}

.mrg-action-menu-trigger [data-slot="action-menu-trigger-label"] {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-action-menu-trigger [data-slot="action-menu-trigger-indicator"] {
  flex: none;
}

.mrg-action-menu-trigger[data-hovered]:not([data-disabled]):not([data-pending="true"]),
.mrg-action-menu-trigger[data-pressed]:not([data-disabled]):not([data-pending="true"]) {
  background: var(--mrg-semantic-color-background-surface);
}

.mrg-action-menu-trigger[data-focus-visible],
.mrg-action-menu-item[data-focus-visible] {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-action-menu-trigger[data-disabled] {
  border-color: var(--mrg-semantic-color-border-disabled);
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

.mrg-action-menu-trigger[data-pending="true"] {
  cursor: progress;
}

.mrg-action-menu-popover {
  --mrg-action-menu-z-index: 20;
  background: var(--mrg-semantic-color-background-surface-raised);
  border-radius: var(--mrg-semantic-radius-overlay);
  box-shadow: 0 var(--mrg-semantic-space-inline-xs) var(--mrg-semantic-space-inline-sm)
    var(--mrg-semantic-color-overlay-scrim);
  box-sizing: border-box;
  max-block-size: min(var(--available-height), 22rem);
  max-inline-size: min(var(--trigger-width), calc(100vw - 2 * var(--mrg-semantic-space-stack-md)));
  min-inline-size: min(16rem, calc(100vw - 2 * var(--mrg-semantic-space-stack-md)));
  overflow-y: auto;
  transform-origin: var(--trigger-anchor-point);
  z-index: var(--mrg-action-menu-z-index);
}

.mrg-action-menu-popover[data-entering] {
  animation: mrg-action-menu-enter var(--mrg-semantic-motion-duration-transition)
    var(--mrg-semantic-motion-easing-enter);
}

.mrg-action-menu-popover[data-exiting] {
  animation: mrg-action-menu-exit var(--mrg-semantic-motion-duration-feedback)
    var(--mrg-semantic-motion-easing-exit);
}

.mrg-action-menu-popover > [data-slot="layer"] {
  padding: var(--mrg-semantic-space-inline-xs);
}

.mrg-action-menu-content {
  display: flex;
  flex-direction: column;
  gap: var(--mrg-semantic-space-inline-xs);
  outline: none;
}

.mrg-action-menu-item {
  background: transparent;
  border: 0;
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: var(--mrg-semantic-color-foreground-primary);
  cursor: pointer;
  display: flex;
  flex-direction: column;
  font: inherit;
  gap: var(--mrg-semantic-space-inline-xs);
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: 0;
  overflow-wrap: anywhere;
  padding-block: var(--mrg-semantic-space-inline-sm);
  padding-inline: var(--mrg-semantic-space-inline-md);
  text-align: start;
}

.mrg-action-menu-item [data-slot="action-menu-item-label"],
.mrg-action-menu-item [data-slot="action-menu-item-description"] {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-action-menu-item[data-focused],
.mrg-action-menu-item[data-hovered] {
  background: var(--mrg-semantic-color-background-surface-sunken);
}

.mrg-action-menu-item[data-intent="destructive"] {
  color: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-action-menu-item[data-confirming="true"] {
  background: var(--mrg-semantic-color-status-danger-background);
  box-shadow: inset 0 0 0 var(--mrg-semantic-border-width-strong)
    var(--mrg-semantic-color-status-danger-border);
  font-weight: var(--mrg-semantic-font-weight-strong);
}

.mrg-action-menu-item[data-disabled] {
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

.mrg-action-menu-item [data-slot="action-menu-item-description"] {
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
  font-weight: var(--mrg-semantic-font-weight-body);
}

@keyframes mrg-action-menu-enter {
  from {
    opacity: 0;
    transform: translateY(calc(-1 * var(--mrg-semantic-space-inline-xs)));
  }
}

@keyframes mrg-action-menu-exit {
  to {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  .mrg-action-menu-popover[data-entering],
  .mrg-action-menu-popover[data-exiting] {
    animation: none;
  }
}

@media (forced-colors: active) {
  .mrg-action-menu-trigger,
  .mrg-action-menu-popover,
  .mrg-action-menu-item {
    background: Canvas;
    color: CanvasText;
    forced-color-adjust: auto;
  }

  .mrg-action-menu-trigger {
    border-color: ButtonBorder;
  }

  .mrg-action-menu-item[data-intent="destructive"]::before {
    content: "! ";
  }

  .mrg-action-menu-item[data-focused],
  .mrg-action-menu-item[data-confirming="true"] {
    background: Highlight;
    color: HighlightText;
  }

  .mrg-action-menu-item[data-disabled],
  .mrg-action-menu-trigger[data-disabled] {
    color: GrayText;
  }
}

"use client";

import { forwardRef, useId, useState, type ButtonHTMLAttributes, type HTMLAttributes } from "react";
import {
  Button as AriaButton,
  type ButtonProps as AriaButtonProps,
} from "react-aria-components/Button";
import { I18nProvider as AriaI18nProvider } from "react-aria-components/I18nProvider";
import {
  Menu as AriaMenu,
  MenuItem as AriaMenuItem,
  MenuTrigger as AriaMenuTrigger,
  Popover as AriaPopover,
} from "react-aria-components/Menu";

import { useDirection, type DirectionValue } from "../direction/index";
import { LayerManager } from "../layer-manager/index";
import { useMergoraContext } from "../provider/index";
import "./action-menu.css";

interface ActionMenuItemBase {
  readonly id: string;
  readonly label: string;
  readonly disabled?: boolean;
  readonly description?: string;
  readonly onSelect?: () => void;
}

export interface ActionMenuDefaultItem extends ActionMenuItemBase {
  readonly intent?: "default";
  readonly confirmLabel?: never;
}

export interface ActionMenuDestructiveItem extends ActionMenuItemBase {
  readonly intent: "destructive";
  /** Required second-step text, for example “Confirm delete project”. */
  readonly confirmLabel: string;
}

export type ActionMenuItem = ActionMenuDefaultItem | ActionMenuDestructiveItem;
export type ActionMenuPlacement = "start" | "end";

function assertValidActionMenuItemIds(items: readonly ActionMenuItem[]): void {
  const ids = new Set<string>();
  for (const item of items) {
    if (item.id.trim().length === 0) {
      throw new Error("ActionMenu item ids must be non-empty strings.");
    }
    if (ids.has(item.id)) {
      throw new Error(
        `ActionMenu item ids must be unique. Duplicate id: ${JSON.stringify(item.id)}.`,
      );
    }
    ids.add(item.id);
  }
}

export interface ActionMenuProps extends Omit<
  HTMLAttributes<HTMLSpanElement>,
  "children" | "defaultValue" | "onChange"
> {
  readonly label: string;
  readonly items: readonly ActionMenuItem[];
  readonly open?: boolean;
  readonly defaultOpen?: boolean;
  readonly onOpenChange?: (open: boolean) => void;
  readonly onAction?: (id: string) => void;
  readonly direction?: DirectionValue;
  readonly placement?: ActionMenuPlacement;
  readonly pending?: boolean;
  readonly pendingLabel?: string;
  readonly triggerProps?: Omit<
    ButtonHTMLAttributes<HTMLButtonElement>,
    "aria-expanded" | "aria-haspopup" | "children" | "onClick"
  >;
}

/** Kept as a deterministic helper for collection-level contract tests. */
export function resolveMenuIndex(input: {
  readonly current: number;
  readonly itemCount: number;
  readonly key: string;
}): number | null {
  const { current, itemCount, key } = input;
  if (itemCount === 0) return null;
  if (key === "Home") return 0;
  if (key === "End") return itemCount - 1;
  if (key === "ArrowDown") return (current + 1 + itemCount) % itemCount;
  if (key === "ArrowUp") return (current - 1 + itemCount) % itemCount;
  return null;
}

export const ActionMenu = forwardRef<HTMLButtonElement, ActionMenuProps>(function ActionMenu(
  {
    className,
    defaultOpen = false,
    direction,
    items,
    label,
    onAction,
    onOpenChange,
    open,
    pending = false,
    pendingLabel,
    placement = "start",
    triggerProps,
    ...nativeProps
  },
  forwardedRef,
) {
  const layerId = `mrg-action-menu-${useId().replaceAll(":", "")}`;
  const inheritedDirection = useDirection();
  const { locale } = useMergoraContext();
  const resolvedDirection = direction ?? inheritedDirection;
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const [confirmationId, setConfirmationId] = useState<string | null>(null);
  assertValidActionMenuItemIds(items);
  const controlled = open !== undefined;
  const isOpen = pending ? false : (open ?? uncontrolledOpen);
  const usablePendingLabel = pendingLabel?.trim() ? pendingLabel : undefined;
  const triggerLabel = pending && usablePendingLabel !== undefined ? usablePendingLabel : label;
  const ariaPlacement =
    placement === "start"
      ? resolvedDirection === "rtl"
        ? "bottom right"
        : "bottom left"
      : resolvedDirection === "rtl"
        ? "bottom left"
        : "bottom right";
  const {
    "aria-disabled": triggerAriaDisabled,
    className: triggerClassName,
    disabled: triggerDisabled,
    onKeyDown: triggerOnKeyDown,
    ...nativeTriggerProps
  } = triggerProps ?? {};

  const setOpen = (next: boolean): void => {
    if (pending && next) return;
    if (!controlled) setUncontrolledOpen(next);
    if (!next) setConfirmationId(null);
    onOpenChange?.(next);
  };
  const activateItem = (item: ActionMenuItem): void => {
    if (item.disabled) return;
    if (item.intent === "destructive" && confirmationId !== item.id) {
      setConfirmationId(item.id);
      return;
    }
    item.onSelect?.();
    onAction?.(item.id);
  };

  const ariaTriggerProps = nativeTriggerProps as unknown as AriaButtonProps;
  return (
    <AriaI18nProvider locale={locale}>
      <span
        {...nativeProps}
        className={className === undefined ? "mrg-action-menu" : `mrg-action-menu ${className}`}
        data-open={isOpen || undefined}
        data-slot="action-menu"
        dir={resolvedDirection}
        lang={locale}
      >
        <AriaMenuTrigger isOpen={isOpen} onOpenChange={setOpen}>
          <AriaButton
            {...ariaTriggerProps}
            {...(pending
              ? { "aria-disabled": true }
              : triggerAriaDisabled === undefined
                ? {}
                : { "aria-disabled": triggerAriaDisabled })}
            {...(pending ? { "aria-busy": true, "data-pending": true } : {})}
            {...(triggerDisabled === undefined ? {} : { isDisabled: triggerDisabled })}
            {...(triggerOnKeyDown === undefined ? {} : { onKeyDown: triggerOnKeyDown })}
            ref={forwardedRef}
            aria-label={triggerLabel}
            className={
              triggerClassName === undefined
                ? "mrg-action-menu-trigger"
                : `mrg-action-menu-trigger ${triggerClassName}`
            }
            data-slot="action-menu-trigger"
          >
            <span data-slot="action-menu-trigger-label">{triggerLabel}</span>
            <span aria-hidden="true" data-slot="action-menu-trigger-indicator">
              ▾
            </span>
          </AriaButton>
          <AriaPopover
            className="mrg-action-menu-popover"
            containerPadding={12}
            data-slot="action-menu-popover"
            offset={8}
            placement={ariaPlacement}
            shouldFlip
          >
            <LayerManager.Layer active dismissible={false} id={`${layerId}-layer`}>
              <AriaMenu
                aria-label={label}
                className="mrg-action-menu-content"
                data-slot="action-menu-content"
              >
                {items.map((item, index) => {
                  const confirming = item.intent === "destructive" && confirmationId === item.id;
                  const descriptionId = `${layerId}-item-${index}-description`;
                  return (
                    <AriaMenuItem
                      {...(item.description === undefined
                        ? {}
                        : { "aria-describedby": descriptionId })}
                      {...(item.disabled === undefined ? {} : { isDisabled: item.disabled })}
                      className="mrg-action-menu-item"
                      data-confirming={confirming || undefined}
                      data-intent={item.intent ?? "default"}
                      data-slot="action-menu-item"
                      id={item.id}
                      key={item.id}
                      onAction={() => activateItem(item)}
                      shouldCloseOnSelect={item.intent !== "destructive" || confirming}
                      textValue={item.label}
                    >
                      <span data-slot="action-menu-item-label">
                        {confirming ? item.confirmLabel : item.label}
                      </span>
                      {item.description === undefined ? null : (
                        <span data-slot="action-menu-item-description" id={descriptionId}>
                          {item.description}
                        </span>
                      )}
                    </AriaMenuItem>
                  );
                })}
              </AriaMenu>
            </LayerManager.Layer>
          </AriaPopover>
        </AriaMenuTrigger>
      </span>
    </AriaI18nProvider>
  );
});

ActionMenu.displayName = "ActionMenu";

export { ActionMenu, resolveMenuIndex } from "./action-menu";
export type {
  ActionMenuDefaultItem,
  ActionMenuDestructiveItem,
  ActionMenuItem,
  ActionMenuPlacement,
  ActionMenuProps,
} from "./action-menu";

.mrg-alert {
  --mrg-alert-background: var(--mrg-semantic-color-status-info-background);
  --mrg-alert-border: var(--mrg-semantic-color-status-info-border);
  --mrg-alert-foreground: var(--mrg-semantic-color-status-info-foreground);
  align-items: start;
  background: var(--mrg-alert-background);
