.mrg-dialog__overlay {
  position: fixed;
  z-index: calc(
    var(
        --mrg-component-layer-stack-base,
        var(--mrg-component-dialog-layer, var(--mrg-semantic-layer-modal))
      ) +
      var(--mrg-layer-index, 0)
  );
  inset: 0;
  display: grid;
  box-sizing: border-box;
  place-items: center;
  overflow: auto;
  overscroll-behavior: contain;
  padding-block: max(
    var(--mrg-semantic-space-stack-md),
    env(safe-area-inset-top, 0px),
    env(safe-area-inset-bottom, 0px)
  );
  padding-inline: max(
    var(--mrg-semantic-space-stack-md),
    env(safe-area-inset-left, 0px),
    env(safe-area-inset-right, 0px)
  );
  background: var(--mrg-component-dialog-scrim, var(--mrg-semantic-color-overlay-scrim));
  isolation: isolate;
}

.mrg-dialog__overlay[data-modal="false"] {
  position: absolute;
  display: block;
  inset: auto;
  max-block-size: min(var(--available-height, 80dvb), calc(100dvb - 1rem));
  max-inline-size: min(
    var(--mrg-semantic-size-content-prose),
    calc(100dvi - var(--mrg-semantic-space-stack-md) - var(--mrg-semantic-space-stack-md))
  );
  overflow: visible;
  padding: 0;
  background: transparent;
  isolation: auto;
}

.mrg-dialog__positioner {
  box-sizing: border-box;
  inline-size: min(
    var(--mrg-semantic-size-content-prose),
    calc(
      var(--visual-viewport-width, 100dvi) - var(--mrg-semantic-space-stack-md) -
        var(--mrg-semantic-space-stack-md)
