  max-inline-size: 100%;
  margin-block: auto;
}

.mrg-dialog__keyboard-boundary {
  inline-size: 100%;
}

.mrg-dialog__content {
  box-sizing: border-box;
  max-block-size: calc(
    var(--visual-viewport-height, 100dvb) - var(--mrg-semantic-space-stack-md) -
