.mrg-radio-group {
  border: 0;
  color: var(--mrg-semantic-color-foreground-primary);
  font-family: var(--mrg-semantic-font-family-prose);
  margin: 0;
  min-inline-size: 0;
  padding: 0;
}

.mrg-radio-group [data-slot="radio-group-label"] {
  font-weight: var(--mrg-semantic-font-weight-label);
  padding: 0;
}

.mrg-radio-group [data-slot="radio-group-description"],
.mrg-radio-group [data-slot="radio-group-error"] {
  font-size: var(--mrg-semantic-font-size-label);
  margin-block: var(--mrg-semantic-space-stack-xs) 0;
  max-inline-size: 70ch;
  overflow-wrap: anywhere;
}

.mrg-radio-group [data-slot="radio-group-description"],
.mrg-radio-group [data-slot="radio-group-item-description"] {
  color: var(--mrg-semantic-color-foreground-muted);
}

.mrg-radio-group [data-slot="radio-group-error"] {
  color: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-radio-group [data-slot="radio-group-items"] {
  display: flex;
  flex-direction: column;
  gap: var(--mrg-semantic-space-stack-sm);
  margin-block-start: var(--mrg-semantic-space-stack-sm);
  min-inline-size: 0;
}

.mrg-radio-group[data-layout="inline"] [data-slot="radio-group-items"] {
  flex-direction: row;
  flex-wrap: wrap;
}

.mrg-radio-group[data-layout="columns"] [data-slot="radio-group-items"] {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 14rem), 1fr));
}

.mrg-radio-group-item {
  cursor: pointer;
  display: grid;
  gap: var(--mrg-semantic-space-stack-xs);
  min-block-size: var(--mrg-semantic-size-target-minimum);
  min-inline-size: 0;
  position: relative;
}

.mrg-radio-group-item [data-slot="radio-group-item-label-root"] {
  align-items: start;
  cursor: inherit;
  display: grid;
  gap: var(--mrg-semantic-space-inline-sm);
  grid-template-columns: var(--mrg-semantic-size-target-minimum) minmax(0, 1fr);
  min-inline-size: 0;
}

.mrg-radio-group-item[data-variant="card"] {
  background: var(--mrg-semantic-color-background-surface);
  border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-default);
  border-radius: var(--mrg-semantic-radius-control);
  padding: var(--mrg-semantic-space-inline-md);
}

.mrg-radio-group-item[data-state="checked"][data-variant="card"] {
  border-color: var(--mrg-semantic-color-selection-border);
}

.mrg-radio-group-item [data-slot="radio-group-input"] {
  appearance: none;
  block-size: var(--mrg-semantic-size-target-minimum);
  cursor: inherit;
  grid-column: 1;
  grid-row: 1;
  inline-size: var(--mrg-semantic-size-target-minimum);
  margin: 0;
  opacity: 0;
  z-index: 1;
}

.mrg-radio-group-item [data-slot="radio-group-indicator"] {
  align-items: center;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: 50%;
  block-size: var(--mrg-semantic-size-target-minimum);
  display: flex;
  grid-column: 1;
  grid-row: 1;
  inline-size: var(--mrg-semantic-size-target-minimum);
  justify-content: center;
}

.mrg-radio-group-item[data-state="checked"] [data-slot="radio-group-indicator"]::after {
  background: var(--mrg-semantic-color-selection-border);
  border-radius: 50%;
  block-size: 0.65rem;
  content: "";
  inline-size: 0.65rem;
}

.mrg-radio-group-item
  [data-slot="radio-group-input"]:focus-visible
  + [data-slot="radio-group-indicator"] {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-radio-group-item [data-slot="radio-group-item-label"] {
  grid-column: 2;
  line-height: var(--mrg-semantic-font-line-height-body);
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-radio-group-item [data-slot="radio-group-item-description"] {
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
  line-height: var(--mrg-semantic-font-line-height-body);
  margin-inline-start: calc(
    var(--mrg-semantic-size-target-minimum) + var(--mrg-semantic-space-inline-sm)
  );
  max-inline-size: 70ch;
  overflow-wrap: anywhere;
}

.mrg-radio-group-item[data-disabled="true"] {
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

@media (pointer: coarse) {
  .mrg-radio-group-item,
  .mrg-radio-group-item [data-slot="radio-group-item-label-root"] {
    min-block-size: var(--mrg-semantic-size-target-preferred);
  }

  .mrg-radio-group-item [data-slot="radio-group-item-label-root"] {
    align-items: center;
  }
}

@media (max-width: 30rem) {
  .mrg-radio-group[data-layout="inline"] [data-slot="radio-group-items"] {
    align-items: stretch;
    flex-direction: column;
  }
}

@media (forced-colors: active) {
  .mrg-radio-group-item [data-slot="radio-group-indicator"] {
    background: Field;
    border-color: FieldText;
  }

  .mrg-radio-group-item[data-state="checked"] [data-slot="radio-group-indicator"]::after {
    background: Highlight;
  }

  .mrg-radio-group-item[data-variant="card"] {
    border-color: CanvasText;
  }
}

"use client";

import {
  Children,
  Fragment,
  createContext,
  forwardRef,
  isValidElement,
  useCallback,
  useContext,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
  type FieldsetHTMLAttributes,
  type ForwardedRef,
  type InputHTMLAttributes,
  type KeyboardEventHandler,
  type ReactNode,
  type CSSProperties,
} from "react";

import { mergeFieldIdRefs } from "../field/index";
import "./radio-group.css";

export type RadioGroupLayout = "stacked" | "inline" | "columns";
export type RadioGroupDirection = "ltr" | "rtl";

export interface RadioGroupProps extends Omit<
  FieldsetHTMLAttributes<HTMLFieldSetElement>,
  "children" | "defaultValue" | "onChange"
> {
  readonly children?: ReactNode;
  readonly defaultValue?: string;
  readonly description?: ReactNode;
  readonly direction?: RadioGroupDirection;
  readonly error?: ReactNode;
  readonly label: ReactNode;
  readonly layout?: RadioGroupLayout;
  readonly name: string;
  readonly onValueChange?: (value: string) => void;
  readonly required?: boolean;
  readonly value?: string;
}

interface RadioGroupContextValue {
  readonly ariaInvalid: InputHTMLAttributes<HTMLInputElement>["aria-invalid"];
  readonly descriptionId: string | undefined;
  readonly disabled: boolean;
  readonly errorMessageId: string | undefined;
  readonly form: string | undefined;
  readonly name: string;
  readonly required: boolean;
  readonly select: (value: string) => void;
  readonly selected: string | undefined;
}

const RadioGroupContext = createContext<RadioGroupContextValue | null>(null);

interface RadioGroupItemInspection {
  readonly value: string;
}

function inspectRadioGroupItems(children: ReactNode): readonly RadioGroupItemInspection[] {
  const items: RadioGroupItemInspection[] = [];
  Children.forEach(children, (child) => {
    if (!isValidElement<{ readonly children?: ReactNode }>(child)) return;
    if (child.type === Fragment) {
      items.push(...inspectRadioGroupItems(child.props.children));
      return;
    }
    if (child.type !== RadioGroupItem) return;
    const props = child.props as RadioGroupItemProps;
    items.push({ value: props.value });
  });
  return items;
}

function validateNonBlank(value: string, name: string): void {
  if (value.trim().length === 0) {
    throw new RangeError(`Mergora RadioGroup ${name} must not be empty or whitespace-only.`);
  }
}

interface ProcessLike {
  readonly env?: { readonly NODE_ENV?: string };
}

function isDevelopmentRuntime(): boolean {
  const viteProduction = (
    import.meta as ImportMeta & { readonly env?: { readonly PROD?: boolean } }
  ).env?.PROD;
  const runtime = globalThis as typeof globalThis & { readonly process?: ProcessLike };
  return viteProduction !== true && runtime.process?.env?.NODE_ENV !== "production";
}

function hasAccessibleContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasAccessibleContent);
  if (isValidElement<{ readonly children?: ReactNode }>(value)) {
    if (value.type === Fragment) return hasAccessibleContent(value.props.children);
    return typeof value.type === "string" ? hasAccessibleContent(value.props.children) : true;
  }
  return true;
}

function isSemanticallyInvalid(
  value: InputHTMLAttributes<HTMLInputElement>["aria-invalid"],
): boolean {
  return value === true || value === "true" || value === "grammar" || value === "spelling";
}

export function resolveRadioGroupIndex(input: {
  readonly current: number;
  readonly direction: RadioGroupDirection;
  readonly itemCount: number;
  readonly key: string;
}): number | null {
  const { current, direction, itemCount, key } = input;
  if (itemCount <= 0 || current < 0) return null;
  if (key === "Home") return 0;
  if (key === "End") return itemCount - 1;
  let delta = 0;
  if (key === "ArrowDown") delta = 1;
  else if (key === "ArrowUp") delta = -1;
  else if (key === "ArrowRight") delta = direction === "rtl" ? -1 : 1;
  else if (key === "ArrowLeft") delta = direction === "rtl" ? 1 : -1;
  return delta === 0 ? null : (current + delta + itemCount) % itemCount;
}

function setForwardedRef<T>(ref: ForwardedRef<T>, value: T | null): void {
  if (typeof ref === "function") ref(value);
  else if (ref !== null) ref.current = value;
}

export const RadioGroup = forwardRef<HTMLFieldSetElement, RadioGroupProps>(function RadioGroup(
  {
    "aria-describedby": ariaDescribedBy,
    children,
    className,
    defaultValue,
    description,
    direction,
    disabled = false,
    error,
    form,
    label,
    layout = "stacked",
    name,
    onValueChange,
    required = false,
    value,
    ...nativeProps
  },
  forwardedRef,
) {
  const generatedId = useId().replaceAll(":", "");
  const rootRef = useRef<HTMLFieldSetElement | null>(null);
  const controlled = value !== undefined;
  const [uncontrolledValue, setUncontrolledValue] = useState(defaultValue);
  const selected = controlled ? value : uncontrolledValue;
  validateNonBlank(name, "name");
  const itemInspection = inspectRadioGroupItems(children);
  const itemValues = new Set<string>();
  for (const item of itemInspection) {
    validateNonBlank(item.value, "item value");
    if (itemValues.has(item.value)) {
      throw new RangeError(`Mergora RadioGroup received duplicate item value "${item.value}".`);
    }
    itemValues.add(item.value);
  }
  const hasDescription = hasAccessibleContent(description);
  const hasError = hasAccessibleContent(error);
  const descriptionId = hasDescription ? `mrg-radio-group-${generatedId}-description` : undefined;
  const errorId = hasError ? `mrg-radio-group-${generatedId}-error` : undefined;
  const describedBy = mergeFieldIdRefs(ariaDescribedBy, descriptionId, errorId);
  const explicitAriaInvalid = nativeProps["aria-invalid"];
  const resolvedAriaInvalid =
    explicitAriaInvalid === undefined ? hasError || undefined : explicitAriaInvalid;
  const invalid = hasError || isSemanticallyInvalid(explicitAriaInvalid);

  useEffect(() => {
    if (!isDevelopmentRuntime()) return;
    if (!hasAccessibleContent(label)) {
      console.warn("Mergora RadioGroup requires a non-empty visible label.");
    }
    if (itemInspection.length === 0) {
      console.warn("Mergora RadioGroup requires at least one direct RadioGroupItem.");
    }
    if (selected !== undefined && !itemValues.has(selected)) {
      console.warn(`Mergora RadioGroup selection has no direct item for value "${selected}".`);
    }
  }, [itemInspection.length, label, selected]);

  useEffect(() => {
    const form = rootRef.current?.querySelector<HTMLInputElement>(
      '[data-slot="radio-group-input"]',
    )?.form;
    if (form === null || form === undefined) return;
    let timer: ReturnType<typeof setTimeout> | undefined;
    const handleReset = () => {
      timer = setTimeout(() => {
        if (!controlled) setUncontrolledValue(defaultValue);
      }, 0);
    };
    form.addEventListener("reset", handleReset);
    return () => {
      form.removeEventListener("reset", handleReset);
      if (timer !== undefined) clearTimeout(timer);
    };
  }, [controlled, defaultValue, form]);

  const select = useCallback(
    (next: string) => {
      if (disabled || next === selected) return;
      if (!controlled) setUncontrolledValue(next);
      onValueChange?.(next);
    },
    [controlled, disabled, onValueChange, selected],
  );
  const context = useMemo<RadioGroupContextValue>(
    () => ({
      ariaInvalid: resolvedAriaInvalid,
      descriptionId,
      disabled,
      errorMessageId: errorId,
      form,
      name,
      required,
      select,
      selected,
    }),
    [descriptionId, disabled, errorId, form, name, required, resolvedAriaInvalid, select, selected],
  );
  const assignRoot = useCallback(
    (node: HTMLFieldSetElement | null) => {
      rootRef.current = node;
      setForwardedRef(forwardedRef, node);
    },
    [forwardedRef],
  );
  const handleKeyDown: KeyboardEventHandler<HTMLDivElement> = (event) => {
    if (event.defaultPrevented) return;
    if (!(event.target instanceof HTMLInputElement)) return;
    const inputs = [
      ...event.currentTarget.querySelectorAll<HTMLInputElement>(
        '[data-slot="radio-group-input"]:not(:disabled)',
      ),
    ];
    const current = inputs.indexOf(event.target);
    const inheritedDirection = window.getComputedStyle(event.currentTarget).direction;
    const resolvedDirection: RadioGroupDirection =
      direction ?? (inheritedDirection === "rtl" ? "rtl" : "ltr");
    const next = resolveRadioGroupIndex({
      current,
      direction: resolvedDirection,
      itemCount: inputs.length,
      key: event.key,
    });
    if (next === null) return;
    const target = inputs[next];
    if (target === undefined) return;
    event.preventDefault();
    target.focus();
    target.click();
  };

  return (
    <RadioGroupContext.Provider value={context}>
      <fieldset
        {...nativeProps}
        aria-describedby={describedBy}
        aria-invalid={resolvedAriaInvalid}
        className={className === undefined ? "mrg-radio-group" : `mrg-radio-group ${className}`}
        data-disabled={disabled || undefined}
        data-invalid={invalid || undefined}
        data-layout={layout}
        data-slot="radio-group"
        dir={direction}
        disabled={disabled}
        form={form}
        ref={assignRoot}
      >
        <legend data-slot="radio-group-label">{label}</legend>
        {!hasDescription ? null : (
          <p data-slot="radio-group-description" id={descriptionId}>
            {description}
          </p>
        )}
        <div data-slot="radio-group-items" onKeyDown={handleKeyDown}>
          {children}
        </div>
        {!hasError ? null : (
          <p data-slot="radio-group-error" id={errorId}>
            {error}
          </p>
        )}
      </fieldset>
    </RadioGroupContext.Provider>
  );
});

RadioGroup.displayName = "RadioGroup";

export interface RadioGroupItemProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "checked" | "children" | "defaultChecked" | "name" | "onChange" | "required" | "type"
> {
  readonly children: ReactNode;
  readonly description?: ReactNode;
  readonly rootClassName?: string;
  readonly rootStyle?: CSSProperties;
  readonly value: string;
  readonly variant?: "plain" | "card";
}

export const RadioGroupItem = forwardRef<HTMLInputElement, RadioGroupItemProps>(
  function RadioGroupItem(
    {
      "aria-describedby": ariaDescribedBy,
      "aria-errormessage": ariaErrorMessage,
      "aria-invalid": ariaInvalid,
      "aria-label": ariaLabel,
      "aria-labelledby": ariaLabelledBy,
      children,
      className,
      description,
      disabled = false,
      form,
      rootClassName,
      rootStyle,
      style,
      value,
      variant = "plain",
      ...nativeProps
    },
    ref,
  ) {
    const context = useContext(RadioGroupContext);
    if (context === null) throw new Error("Mergora RadioGroupItem requires a RadioGroup ancestor.");
    validateNonBlank(value, "item value");
    const generatedId = useId().replaceAll(":", "");
    const hasDescription = hasAccessibleContent(description);
    const descriptionId = hasDescription ? `mrg-radio-item-${generatedId}-description` : undefined;
    const resolvedDisabled = context.disabled || disabled;
    const checked = context.selected === value;
    const resolvedAriaInvalid = ariaInvalid === undefined ? context.ariaInvalid : ariaInvalid;
    const semanticInvalid = isSemanticallyInvalid(resolvedAriaInvalid);
    const errorMessage = mergeFieldIdRefs(
      ariaErrorMessage,
      semanticInvalid ? context.errorMessageId : undefined,
    );

    useEffect(() => {
      if (
        isDevelopmentRuntime() &&
        !hasAccessibleContent(children) &&
        (ariaLabel === undefined || ariaLabel.trim().length === 0) &&
        (ariaLabelledBy === undefined || ariaLabelledBy.trim().length === 0)
      ) {
        console.warn(
          `Mergora RadioGroupItem value "${value}" requires children, aria-label, or aria-labelledby.`,
        );
      }
    }, [ariaLabel, ariaLabelledBy, children, value]);
    return (
      <div
        className={
          rootClassName === undefined
            ? "mrg-radio-group-item"
            : `mrg-radio-group-item ${rootClassName}`
        }
        data-disabled={resolvedDisabled || undefined}
        data-invalid={semanticInvalid || undefined}
        data-slot="radio-group-item"
        data-state={checked ? "checked" : "unchecked"}
        data-variant={variant}
        style={rootStyle}
      >
        <label data-slot="radio-group-item-label-root">
          <input
            {...nativeProps}
            aria-label={ariaLabel}
            aria-labelledby={ariaLabelledBy}
            aria-describedby={mergeFieldIdRefs(
              ariaDescribedBy,
              context.descriptionId,
              semanticInvalid ? context.errorMessageId : undefined,
              descriptionId,
            )}
            aria-errormessage={errorMessage}
            aria-invalid={resolvedAriaInvalid}
            checked={checked}
            className={className}
            data-slot="radio-group-input"
            disabled={resolvedDisabled}
            form={form ?? context.form}
            name={context.name}
            onChange={() => context.select(value)}
            ref={ref}
            required={context.required}
            style={style}
            type="radio"
            value={value}
          />
          <span aria-hidden="true" data-slot="radio-group-indicator" />
          <span data-slot="radio-group-item-label">{children}</span>
        </label>
        {!hasDescription ? null : (
          <span data-slot="radio-group-item-description" id={descriptionId}>
            {description}
          </span>
        )}
      </div>
    );
  },
);

RadioGroupItem.displayName = "RadioGroupItem";

export const RadioGroupParts = { Root: RadioGroup, Item: RadioGroupItem } as const;

export {
  clampResizableValue,
  formatResizableValue,
  Resizable,
  ResizableHandle,
  ResizablePrimary,
  ResizableRoot,
  ResizableSecondary,
} from "./resizable";
export type {
  ResizableChangeDetails,
  ResizableChangeReason,
  ResizableHandleProps,
  ResizableMessages,
  ResizableOrientation,
  ResizablePrimaryProps,
  ResizableRootProps,
  ResizableSecondaryProps,
} from "./resizable";

.mrg-resizable {
  align-items: stretch;
  box-sizing: border-box;
  display: flex;
  inline-size: 100%;
  min-block-size: 0;
  min-inline-size: 0;
}

.mrg-resizable[data-orientation="horizontal"] {
  flex-direction: row;
}

.mrg-resizable[data-orientation="vertical"] {
  flex-direction: column;
}

.mrg-resizable__primary,
.mrg-resizable__secondary {
  box-sizing: border-box;
  min-block-size: 0;
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-resizable[data-orientation="horizontal"] > .mrg-resizable__primary {
  flex: 0 1 var(--mrg-resizable-value);
  inline-size: var(--mrg-resizable-value);
}

.mrg-resizable[data-orientation="vertical"] > .mrg-resizable__primary {
  block-size: var(--mrg-resizable-value);
  flex: 0 1 var(--mrg-resizable-value);
}

.mrg-resizable__secondary {
  flex: 1 1 0;
}

.mrg-resizable__handle {
  align-items: center;
  background: var(--mrg-semantic-color-background-surface);
  display: flex;
  flex: 0 0 auto;
  gap: var(--mrg-semantic-space-inline-xs);
  justify-content: center;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
}

.mrg-resizable__handle[data-orientation="horizontal"] {
  flex-direction: column;
  padding-block: var(--mrg-semantic-space-inline-xs);
}

.mrg-resizable__handle[data-orientation="vertical"] {
  flex-direction: row;
  padding-inline: var(--mrg-semantic-space-inline-xs);
}

.mrg-resizable__separator {
  align-items: center;
  background: var(--mrg-semantic-color-background-surface-sunken);
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  cursor: col-resize;
  display: flex;
  flex: 0 0 auto;
  justify-content: center;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  touch-action: none;
}

.mrg-resizable__separator[data-orientation="vertical"] {
  cursor: row-resize;
}

.mrg-resizable__separator:focus-visible,
.mrg-resizable__controls button:focus-visible {
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-resizable__grip {
  background: var(--mrg-semantic-color-border-strong);
  border-radius: var(--mrg-semantic-radius-pill);
  block-size: var(--mrg-semantic-space-stack-lg);
  inline-size: var(--mrg-semantic-border-width-strong);
}

.mrg-resizable__separator[data-orientation="vertical"] .mrg-resizable__grip {
  block-size: var(--mrg-semantic-border-width-strong);
  inline-size: var(--mrg-semantic-space-stack-lg);
}

.mrg-resizable__controls {
  display: flex;
  flex-wrap: wrap;
  gap: var(--mrg-semantic-space-inline-xs);
  justify-content: center;
}

.mrg-resizable__handle[data-orientation="horizontal"] .mrg-resizable__controls {
  flex-direction: column;
}

.mrg-resizable__controls button {
  align-items: center;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  color: var(--mrg-semantic-color-foreground-primary);
  display: inline-flex;
  font: inherit;
  justify-content: center;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  padding: 0;
}

.mrg-resizable__controls button:disabled {
  border-color: var(--mrg-semantic-color-border-disabled);
  color: var(--mrg-semantic-color-foreground-disabled);
  cursor: not-allowed;
}

.mrg-resizable[data-disabled="true"] .mrg-resizable__separator {
  cursor: not-allowed;
  opacity: var(--mrg-semantic-opacity-disabled);
}

@media (forced-colors: active) {
