function assertNoSkeletonSemanticOverrides(props: Readonly<Record<string, unknown>>): void {
  for (const key of [
    "aria-atomic",
    "aria-hidden",
    "aria-label",
    "aria-labelledby",
    "aria-live",
    "children",
    "role",
  ] as const) {
    if (props[key] !== undefined) {
      throw new Error(`Mergora Skeleton owns ${key} and does not accept a semantic override.`);
    }
